      "Preferred photo requirements (what angles/shots) and report format/length constraints",
      "Any safety requirements or restricted areas"
    ],
    "constraints": {
      "budgetCurrency": "USD",
      "budgetMin": 300,
      "budgetMax": 500,
      "timeWindow": {
        "end": "tomorrow_before_5pm",
