        "onsite_visit"
      ],
      "requiresHumanPresence": true,
      "requiresLocalAccess": true,
      "requiresVerifiedEvidence": true,
      "requiresScheduling": true,
      "requiresGeography": true,
      "riskTier": "medium"
    },
    "verificationPlan": {
      "requiredArtifactKinds": [
        "photo_evidence",
