        "short written report identifies any issues"
      ],
      "mustHaveOwnerAcceptance": false,
      "mustHaveLocationSignal": true,
      "mustHaveSignature": false,
      "verificationRequirements": {
        "photoEvidenceMustBeTimestamped": true
      }
