      {
        "phaseKey": "compile_short_written_report",
        "title": "Send short written report summarizing findings and issues"
      }
    ],
    "roleSlots": [
      {
        "roleKey": "field_inspector",
        "requiredActorKinds": [
          "human"
        ],
        "required": true
      }
